{
  "title": "Erreur de réponse Express",
  "group": "Pièges d'API",
  "options": [
    { "text": "Envoie l'objet d'erreur complet" },
    { "text": "Envoie {\"error\":{}}" },
    { "text": "Lève une erreur serveur" },
    { "text": "Envoie uniquement le message d'erreur" }
  ],
  "questionProse": ["Qu'est-ce qui est envoyé au client ?"],
  "explanationProse": ["`res.json()` utilise `JSON.stringify()` en interne, donc l'objet Error devient `{}`. Le client reçoit `{\"error\":{}}`. Pour corriger cela, utilisez `res.json({ error: error.message })` ou `res.json({ error: { message: error.message, name: error.name } })`."]
}
